@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

@* ───── Step Indicator Bar ───── *@
<nav class="d-flex justify-content-between mb-4 position-relative apply-steps" aria-label="Application steps">
    @for (int i = 0; i < StepLabels.Length; i++)
    {
        var step = i + 1;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var isFuture = step > CurrentStep;

        <button type="button"
                class="btn border-0 d-flex flex-column align-items-center flex-fill apply-step
                       @(isCurrent ? "fw-bold text-primary" : "")
                       @(isCompleted ? "text-success cursor-pointer" : "")
                       @(isFuture ? "text-muted" : "")"
                disabled="@(isFuture || _submitting)"
                @onclick="() => GoToStep(step)">
            <span class="rounded-circle d-flex align-items-center justify-content-center mb-1
                         @(isCurrent ? "bg-primary text-white" : "")
                         @(isCompleted ? "bg-success text-white" : "")
                         @(isFuture ? "bg-secondary text-white opacity-50" : "")"
                  style="width:32px;height:32px;font-size:.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    @step
                }
            </span>
            <small>@StepLabels[i]</small>
        </button>
    }
</nav>

<hr />

@* ───── Validation / Error Messages ───── *@
@if (_errors.Count > 0)
{
    <div class="alert alert-danger" role="alert">
        <ul class="mb-0">
            @foreach (var err in _errors)
            {
                <li>@err</li>
            }
        </ul>
    </div>
}

@* ───── Step Content ───── *@
@if (_submitted)
{
    <div class="alert alert-success text-center py-5">
        <h3>Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@_applicationId</strong>.</p>
        <p>We'll be in touch soon.</p>
    </div>
}
else
{
    switch (CurrentStep)
    {
        case 1:
            <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                              FullNameChanged="v => _fullName = v"
                              EmailChanged="v => _email = v"
                              PhoneChanged="v => _phone = v"
                              AddressChanged="v => _address = v" />
            break;
        case 2:
            <StepWorkHistory Entries="_workEntries" />
            break;
        case 3:
            <StepReferences References="_references" />
            break;
        case 4:
            <StepCoverLetter Text="@_coverLetter" TextChanged="v => _coverLetter = v" />
            break;
        case 5:
            <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                        WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                        OnEditSection="GoToStep" />
            break;
    }

    @* ───── Navigation Buttons ───── *@
    <div class="d-flex justify-content-between mt-4">
