@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

@* ───── Step Indicator Bar ───── *@
<nav class="d-flex justify-content-between mb-4 position-relative apply-steps" aria-label="Application steps">
    @for (int i = 0; i < StepLabels.Length; i++)
    {
        var step = i + 1;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var isFuture = step > CurrentStep;

        <button type="button"
                class="btn border-0 d-flex flex-column align-items-center flex-fill apply-step
                       @(isCurrent ? "fw-bold text-primary" : "")
                       @(isCompleted ? "text-success cursor-pointer" : "")
                       @(isFuture ? "text-muted" : "")"
                disabled="@(isFuture || _submitting)"
                @onclick="() => GoToStep(step)">
            <span class="rounded-circle d-flex align-items-center justify-content-center mb-1
                         @(isCurrent ? "bg-primary text-white" : "")
                         @(isCompleted ? "bg-success text-white" : "")
                         @(isFuture ? "bg-secondary text-white opacity-50" : "")"
                  style="width:32px;height:32px;font-size:.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    @step
                }
            </span>
            <small>@StepLabels[i]</small>
        </button>
    }
</nav>

<hr />

@* ───── Validation / Error Messages ───── *@
@if (_errors.Count > 0)
{
    <div class="alert alert-danger" role="alert">
        <ul class="mb-0">
            @foreach (var err in _errors)
            {
                <li>@err</li>
            }
        </ul>
    </div>
}

@* ───── Step Content ───── *@
@if (_submitted)
{
    <div class="alert alert-success text-center py-5">
        <h3>Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@_applicationId</strong>.</p>
        <p>We'll be in touch soon.</p>
    </div>
}
else
{
    switch (CurrentStep)
    {
        case 1:
            <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                              FullNameChanged="v => _fullName = v"
                              EmailChanged="v => _email = v"
                              PhoneChanged="v => _phone = v"
                              AddressChanged="v => _address = v" />
            break;
        case 2:
            <StepWorkHistory Entries="_workEntries" />
            break;
        case 3:
            <StepReferences References="_references" />
            break;
        case 4:
            <StepCoverLetter Text="@_coverLetter" TextChanged="v => _coverLetter = v" />
            break;
        case 5:
            <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                        WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                        OnEditSection="GoToStep" />
            break;
    }

    @* ───── Navigation Buttons ───── *@
    <div class="d-flex justify-content-between mt-4">
        @if (CurrentStep > 1)
        {
            <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_submitting">
                &laquo; Back
            </button>
        }
        else
        {
            <span></span>
        }

        @if (CurrentStep < 5)
        {
            <button class="btn btn-primary" @onclick="NextStep" disabled="@_submitting">
                Next &raquo;
            </button>
        }
        else
        {
            <button class="btn btn-success" @onclick="Submit" disabled="@_submitting">
                @if (_submitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        }
    </div>
}

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int CurrentStep { get; set; } = 1;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = "";

    // Submission
    private bool _submitting;
    private bool _submitted;
    private int _applicationId;
    private List<string> _errors = [];

    private void GoToStep(int step)
    {
        if (step < CurrentStep)
        {
            _errors.Clear();
            CurrentStep = step;
        }
    }

    private void PreviousStep()
    {
        _errors.Clear();
        if (CurrentStep > 1) CurrentStep--;
    }

    private async Task NextStep()
    {
        _errors.Clear();

        if (!ValidateCurrentStep())
            return;

        if (CurrentStep == 1)
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(_email);
            if (!emailValid)
            {
                _errors.Add("Please enter a valid email address.");
                return;
            }
        }

        CurrentStep++;
    }

    private bool ValidateCurrentStep()
    {
        switch (CurrentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(_fullName)) _errors.Add("Full name is required.");
                if (string.IsNullOrWhiteSpace(_email)) _errors.Add("Email is required.");
                if (string.IsNullOrWhiteSpace(_phone)) _errors.Add("Phone is required.");
                if (string.IsNullOrWhiteSpace(_address)) _errors.Add("Address is required.");
                break;
            case 2:
                for (int i = 0; i < _workEntries.Count; i++)
                {
                    var e = _workEntries[i];
                    if (string.IsNullOrWhiteSpace(e.Company)) _errors.Add($"Position {i + 1}: Company is required.");
                    if (string.IsNullOrWhiteSpace(e.Title)) _errors.Add($"Position {i + 1}: Job title is required.");
                    if (e.StartDate == default) _errors.Add($"Position {i + 1}: Start date is required.");
                }
                break;
            case 3:
                for (int i = 0; i < _references.Count; i++)
                {
                    var r = _references[i];
                    if (string.IsNullOrWhiteSpace(r.Name)) _errors.Add($"Reference {i + 1}: Name is required.");
                    if (string.IsNullOrWhiteSpace(r.Email)) _errors.Add($"Reference {i + 1}: Email is required.");
                }
                break;
            case 4:
                if (string.IsNullOrWhiteSpace(_coverLetter)) _errors.Add("Cover letter is required.");
                break;
        }

        return _errors.Count == 0;
    }

    private async Task Submit()
    {
        _errors.Clear();
        _submitting = true;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(
                _workEntries.Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch
        {
            _errors.Add("An error occurred while submitting your application. Please try again.");
        }
        finally
        {
            _submitting = false;
        }
    }

    // Mutable models used for form binding
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}
