toolArgs.file_text:
@using static Apply

<h4>References</h4>

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var r = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(i + 1)</h6>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(i)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="r.Name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship</label>
                    <input type="text" class="form-control" @bind="r.Relationship" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="r.Email" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone</label>
                    <input type="tel" class="form-control" @bind="r.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm" @onclick="AddReference">
        + Add Reference
    </button>
}

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = [];

    private void AddReference() => References.Add(new ReferenceModel());

    private void RemoveReference(int index) => References.RemoveAt(index);
}

@using static Apply

<h4>Review &amp; Submit</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3">
                <strong>@entry.Title</strong> at <em>@entry.Company</em><br />
                <small class="text-muted">
                    @entry.StartDate.ToString("MMM yyyy") &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </small>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong>
                @if (!string.IsNullOrWhiteSpace(r.Relationship))
                {
                    <span class="text-muted">(@r.Relationship)</span>
                }
                <br />
                <small>@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"· {r.Phone}" : "")</small>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(4)'>Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

